import React, { useState, useRef } from 'react';

const FoodDetectionApp = () => {
  const [currentImage, setCurrentImage] = useState(null);
  const [imageFile, setImageFile] = useState(null);
  const [detectionResults, setDetectionResults] = useState(null);
  const [ocrResults, setOcrResults] = useState('');
  const [geminiResults, setGeminiResults] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [confidence, setConfidence] = useState(0.5);
  const [statusMessage, setStatusMessage] = useState('준비 완료. 이미지를 로드하세요.');
  const [isDragOver, setIsDragOver] = useState(false);
  const [activeTab, setActiveTab] = useState('camera');
  
  const fileInputRef = useRef(null);

  // 모바일 친화적 아이콘들
  const CameraIcon = () => <span className="text-2xl">📷</span>;
  const UploadIcon = () => <span className="text-xl">📁</span>;
  const EyeIcon = () => <span className="text-lg">👁️</span>;
  const BrainIcon = () => <span className="text-lg">🧠</span>;
  const FileTextIcon = () => <span className="text-lg">📄</span>;
  const SettingsIcon = () => <span className="text-lg">⚙️</span>;
  const CheckIcon = () => <span className="text-lg">✅</span>;
  const LoadingSpinner = () => (
    <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-white"></div>
  );

  // 햅틱 피드백 (지원되는 경우)
  const hapticFeedback = () => {
    if (navigator.vibrate) {
      navigator.vibrate(50);
    }
  };

  // 드래그 앤 드롭 핸들러
  const handleDragOver = (e) => {
    e.preventDefault();
    setIsDragOver(true);
  };

  const handleDragLeave = (e) => {
    e.preventDefault();
    setIsDragOver(false);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setIsDragOver(false);
    
    const files = e.dataTransfer.files;
    if (files.length > 0) {
      const file = files[0];
      if (file.type.startsWith('image/')) {
        handleFileSelect(file);
      } else {
        setStatusMessage('이미지 파일만 업로드 가능합니다.');
        hapticFeedback();
      }
    }
  };

  // 파일 선택 처리
  const handleFileSelect = (file) => {
    console.log('파일 선택됨:', file.name, file.type, file.size);
    setImageFile(file);
    
    if (!file.type.startsWith('image/')) {
      setStatusMessage('이미지 파일만 업로드 가능합니다.');
      hapticFeedback();
      return;
    }
    
    const reader = new FileReader();
    reader.onload = (e) => {
      setCurrentImage(e.target.result);
      setDetectionResults(null);
      setOcrResults('');
      setGeminiResults('');
      setStatusMessage(`이미지 로드 완료: ${file.name}`);
      setActiveTab('image');
      hapticFeedback();
    };
    reader.onerror = (e) => {
      console.error('이미지 로드 실패:', e);
      setStatusMessage('이미지 로드 실패');
      hapticFeedback();
    };
    reader.readAsDataURL(file);
  };

  // 이미지 로드 함수
  const handleImageLoad = (event) => {
    const file = event.target.files[0];
    if (file) {
      handleFileSelect(file);
    }
  };

  // 카메라 캡처 (모바일)
  const handleCameraCapture = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.capture = 'environment'; // 후면 카메라 사용
    input.onchange = (e) => {
      const file = e.target.files[0];
      if (file) {
        handleFileSelect(file);
      }
    };
    input.click();
    hapticFeedback();
  };

  // YOLO 탐지 실행
  const runDetection = async () => {
    if (!imageFile) {
      setStatusMessage('먼저 이미지를 로드하세요.');
      hapticFeedback();
      return;
    }

    setIsProcessing(true);
    setProcessingStep('식품 탐지 중...');
    setStatusMessage('식품 탐지 중...');
    setActiveTab('detection');

    try {
      const formData = new FormData();
      formData.append('file', imageFile);
      formData.append('confidence', confidence);

      const response = await fetch('http://127.0.0.1:8000/detect', {
        method: 'POST',
        body: formData,
      });

      if (response.ok) {
        const result = await response.json();
        setDetectionResults(result);
        setStatusMessage(`식품 탐지 완료: ${result.detections?.length || 0}개 객체 발견`);
        hapticFeedback();
      } else {
        throw new Error('탐지 API 호출 실패');
      }
    } catch (error) {
      setStatusMessage(`식품 탐지 오류: ${error.message}`);
      console.error('Detection error:', error);
      hapticFeedback();
    } finally {
      setIsProcessing(false);
      setProcessingStep('');
    }
  };

  // OCR 및 Gemini 분석 실행
  const runOcrAnalysis = async () => {
    if (!imageFile) {
      setStatusMessage('먼저 이미지를 로드하세요.');
      hapticFeedback();
      return;
    }

    setIsProcessing(true);
    setProcessingStep('텍스트 추출 중...');
    setStatusMessage('텍스트 추출 중...');
    setActiveTab('ocr');

    try {
      const formData = new FormData();
      formData.append('file', imageFile);

      const ocrResponse = await fetch('http://127.0.0.1:8000/ocr', {
        method: 'POST',
        body: formData,
      });

      if (ocrResponse.ok) {
        const ocrResult = await ocrResponse.json();
        setOcrResults(ocrResult.text || '추출된 텍스트가 없습니다.');
        
        if (ocrResult.text) {
          setProcessingStep('AI 분석 중...');
          setStatusMessage('AI 분석 중...');
          setActiveTab('gemini');

          const geminiResponse = await fetch('http://127.0.0.1:8000/analyze', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
            },
            body: JSON.stringify({
              text: ocrResult.text,
              detection_results: detectionResults
            }),
          });

          if (geminiResponse.ok) {
            const geminiResult = await geminiResponse.json();
            setGeminiResults(geminiResult.analysis || '분석 결과가 없습니다.');
            setStatusMessage('분석 완료!');
            hapticFeedback();
          } else {
            setGeminiResults('AI 분석 실패');
            setStatusMessage('텍스트 추출 완료, AI 분석 실패');
            hapticFeedback();
          }
        } else {
          setStatusMessage('텍스트 추출 실패');
          hapticFeedback();
        }
      } else {
        throw new Error('OCR API 호출 실패');
      }
    } catch (error) {
      setStatusMessage(`분석 오류: ${error.message}`);
      console.error('OCR/Analysis error:', error);
      hapticFeedback();
    } finally {
      setIsProcessing(false);
      setProcessingStep('');
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex flex-col">
      {/* 모바일 상단 헤더 */}
      <div className="bg-white shadow-lg rounded-b-3xl p-4 mb-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <CameraIcon />
            <div>
              <h1 className="text-lg font-bold text-gray-800">식품 분석</h1>
              <p className="text-xs text-gray-500">AI 기반 식품 인식</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <SettingsIcon />
            <span className="text-sm font-medium">{confidence.toFixed(1)}</span>
          </div>
        </div>
      </div>

      {/* 메인 콘텐츠 */}
      <div className="flex-1 px-4 pb-20">
        
        {/* 탭 네비게이션 */}
        <div className="bg-white rounded-2xl shadow-lg mb-4 p-2">
          <div className="flex">
            <button
              onClick={() => setActiveTab('camera')}
              className={`flex-1 py-3 px-4 rounded-xl font-medium transition-all duration-200 ${
                activeTab === 'camera' 
                  ? 'bg-blue-500 text-white shadow-md' 
                  : 'text-gray-600'
              }`}
            >
              <div className="flex flex-col items-center gap-1">
                <CameraIcon />
                <span className="text-xs">카메라</span>
              </div>
            </button>
            
            <button
              onClick={() => setActiveTab('image')}
              className={`flex-1 py-3 px-4 rounded-xl font-medium transition-all duration-200 ${
                activeTab === 'image' 
                  ? 'bg-green-500 text-white shadow-md' 
                  : 'text-gray-600'
              }`}
            >
              <div className="flex flex-col items-center gap-1">
                <span className="text-2xl">🖼️</span>
                <span className="text-xs">이미지</span>
              </div>
            </button>
            
            <button
              onClick={() => setActiveTab('detection')}
              className={`flex-1 py-3 px-4 rounded-xl font-medium transition-all duration-200 ${
                activeTab === 'detection' 
                  ? 'bg-purple-500 text-white shadow-md' 
                  : 'text-gray-600'
              }`}
            >
              <div className="flex flex-col items-center gap-1">
                <EyeIcon />
                <span className="text-xs">탐지</span>
              </div>
            </button>
            
            <button
              onClick={() => setActiveTab('ocr')}
              className={`flex-1 py-3 px-4 rounded-xl font-medium transition-all duration-200 ${
                activeTab === 'ocr' 
                  ? 'bg-orange-500 text-white shadow-md' 
                  : 'text-gray-600'
              }`}
            >
              <div className="flex flex-col items-center gap-1">
                <FileTextIcon />
                <span className="text-xs">텍스트</span>
              </div>
            </button>
            
            <button
              onClick={() => setActiveTab('gemini')}
              className={`flex-1 py-3 px-4 rounded-xl font-medium transition-all duration-200 ${
                activeTab === 'gemini' 
                  ? 'bg-red-500 text-white shadow-md' 
                  : 'text-gray-600'
              }`}
            >
              <div className="flex flex-col items-center gap-1">
                <BrainIcon />
                <span className="text-xs">AI분석</span>
              </div>
            </button>
          </div>
        </div>

        {/* 탭 콘텐츠 */}
        <div className="bg-white rounded-2xl shadow-lg p-4 min-h-[60vh]">
          
          {/* 카메라/업로드 탭 */}
          {activeTab === 'camera' && (
            <div className="text-center">
              <h2 className="text-xl font-bold text-gray-800 mb-6">이미지를 선택하세요</h2>
              
              <div className="space-y-4 mb-8">
                {/* 카메라 버튼 */}
                <button
                  onClick={handleCameraCapture}
                  className="w-full py-4 bg-gradient-to-r from-blue-500 to-blue-600 text-white rounded-2xl font-bold text-lg shadow-lg active:scale-95 transition-transform"
                >
                  <div className="flex items-center justify-center gap-3">
                    <CameraIcon />
                    <span>카메라로 촬영</span>
                  </div>
                </button>

                {/* 갤러리 버튼 */}
                <button
                  onClick={() => {
                    fileInputRef.current?.click();
                    hapticFeedback();
                  }}
                  className="w-full py-4 bg-gradient-to-r from-green-500 to-green-600 text-white rounded-2xl font-bold text-lg shadow-lg active:scale-95 transition-transform"
                >
                  <div className="flex items-center justify-center gap-3">
                    <UploadIcon />
                    <span>갤러리에서 선택</span>
                  </div>
                </button>
              </div>

              {/* 신뢰도 설정 */}
              <div className="bg-gray-50 rounded-xl p-4">
                <div className="flex items-center justify-between mb-3">
                  <span className="text-sm font-medium text-gray-700">탐지 민감도</span>
                  <span className="text-sm font-bold text-blue-600">{(confidence * 100).toFixed(0)}%</span>
                </div>
                <input
                  type="range"
                  min="0.1"
                  max="0.9"
                  step="0.1"
                  value={confidence}
                  onChange={(e) => setConfidence(parseFloat(e.target.value))}
                  className="w-full h-3 bg-gray-200 rounded-lg appearance-none cursor-pointer"
                  style={{
                    background: `linear-gradient(to right, #3b82f6 0%, #3b82f6 ${((confidence - 0.1) / 0.8) * 100}%, #e5e7eb ${((confidence - 0.1) / 0.8) * 100}%, #e5e7eb 100%)`
                  }}
                />
                <div className="flex justify-between text-xs text-gray-500 mt-2">
                  <span>낮음</span>
                  <span>높음</span>
                </div>
              </div>

              <input
                type="file"
                accept="image/*"
                onChange={handleImageLoad}
                ref={fileInputRef}
                className="hidden"
              />
            </div>
          )}

          {/* 이미지 표시 탭 */}
          {activeTab === 'image' && (
            <div>
              <h2 className="text-xl font-bold text-gray-800 mb-4">선택된 이미지</h2>
              
              {currentImage ? (
                <div className="space-y-4">
                  <div className="relative">
                    <img
                      src={currentImage}
                      alt="선택된 이미지"
                      className="w-full rounded-xl shadow-md"
                      style={{ maxHeight: '50vh', objectFit: 'contain' }}
                    />
                  </div>
                  
                  {/* 분석 버튼들 */}
                  <div className="grid grid-cols-2 gap-3">
                    <button
                      onClick={runDetection}
                      disabled={isProcessing}
                      className="py-3 bg-gradient-to-r from-purple-500 to-purple-600 text-white rounded-xl font-bold shadow-lg disabled:opacity-50 active:scale-95 transition-transform"
                    >
                      <div className="flex items-center justify-center gap-2">
                        {isProcessing && processingStep.includes('탐지') ? <LoadingSpinner /> : <EyeIcon />}
                        <span className="text-sm">식품 탐지</span>
                      </div>
                    </button>
                    
                    <button
                      onClick={runOcrAnalysis}
                      disabled={isProcessing}
                      className="py-3 bg-gradient-to-r from-orange-500 to-red-500 text-white rounded-xl font-bold shadow-lg disabled:opacity-50 active:scale-95 transition-transform"
                    >
                      <div className="flex items-center justify-center gap-2">
                        {isProcessing && (processingStep.includes('텍스트') || processingStep.includes('AI')) ? <LoadingSpinner /> : <BrainIcon />}
                        <span className="text-sm">AI 분석</span>
                      </div>
                    </button>
                  </div>
                </div>
              ) : (
                <div className="text-center py-12">
                  <div className="text-6xl mb-4">📷</div>
                  <p className="text-gray-500">이미지를 먼저 선택해주세요</p>
                  <button
                    onClick={() => setActiveTab('camera')}
                    className="mt-4 px-6 py-2 bg-blue-500 text-white rounded-xl"
                  >
                    이미지 선택하기
                  </button>
                </div>
              )}
            </div>
          )}

          {/* 탐지 결과 탭 */}
          {activeTab === 'detection' && (
            <div>
              <h2 className="text-xl font-bold text-gray-800 mb-4">식품 탐지 결과</h2>
              
              {detectionResults ? (
                <div className="space-y-3">
                  {detectionResults.detections?.map((detection, index) => (
                    <div key={index} className="bg-gradient-to-r from-blue-50 to-purple-50 rounded-xl p-4 border border-blue-100">
                      <div className="flex justify-between items-center">
                        <div>
                          <h3 className="font-bold text-lg text-blue-800">{detection.class}</h3>
                          {detection.original_class && detection.class === 'other' && (
                            <p className="text-sm text-gray-600">원본: {detection.original_class}</p>
                          )}
                        </div>
                        <div className="text-right">
                          <div 
                            className={`inline-block px-3 py-1 rounded-full text-sm font-bold ${
                              detection.confidence > 0.7 ? 'bg-green-100 text-green-800' : 
                              detection.confidence > 0.4 ? 'bg-yellow-100 text-yellow-800' : 
                              'bg-red-100 text-red-800'
                            }`}
                          >
                            {(detection.confidence * 100).toFixed(1)}%
                          </div>
                        </div>
                      </div>
                    </div>
                  )) || (
                    <div className="text-center py-8">
                      <p className="text-gray-500">탐지된 식품이 없습니다.</p>
                    </div>
                  )}
                </div>
              ) : (
                <div className="text-center py-12">
                  <div className="text-6xl mb-4">👁️</div>
                  <p className="text-gray-500">아직 탐지를 실행하지 않았습니다</p>
                  {currentImage && (
                    <button
                      onClick={runDetection}
                      className="mt-4 px-6 py-2 bg-purple-500 text-white rounded-xl"
                    >
                      탐지 시작하기
                    </button>
                  )}
                </div>
              )}
            </div>
          )}

          {/* OCR 결과 탭 */}
          {activeTab === 'ocr' && (
            <div>
              <h2 className="text-xl font-bold text-gray-800 mb-4">추출된 텍스트</h2>
              
              {ocrResults ? (
                <div className="bg-gray-50 rounded-xl p-4 min-h-[200px]">
                  <p className="text-gray-800 leading-relaxed whitespace-pre-wrap">
                    {ocrResults}
                  </p>
                </div>
              ) : (
                <div className="text-center py-12">
                  <div className="text-6xl mb-4">📄</div>
                  <p className="text-gray-500">아직 텍스트를 추출하지 않았습니다</p>
                  {currentImage && (
                    <button
                      onClick={runOcrAnalysis}
                      className="mt-4 px-6 py-2 bg-orange-500 text-white rounded-xl"
                    >
                      텍스트 추출하기
                    </button>
                  )}
                </div>
              )}
            </div>
          )}

          {/* Gemini 분석 결과 탭 */}
          {activeTab === 'gemini' && (
            <div>
              <h2 className="text-xl font-bold text-gray-800 mb-4">AI 분석 결과</h2>
              
              {geminiResults ? (
                <div className="bg-gradient-to-br from-green-50 to-blue-50 rounded-xl p-4 min-h-[200px] border border-green-100">
                  <p className="text-gray-800 leading-relaxed whitespace-pre-wrap">
                    {geminiResults}
                  </p>
                </div>
              ) : (
                <div className="text-center py-12">
                  <div className="text-6xl mb-4">🧠</div>
                  <p className="text-gray-500">아직 AI 분석을 실행하지 않았습니다</p>
                  {currentImage && (
                    <button
                      onClick={runOcrAnalysis}
                      className="mt-4 px-6 py-2 bg-red-500 text-white rounded-xl"
                    >
                      AI 분석하기
                    </button>
                  )}
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* 하단 상태바 - 모바일 하단에 고정 */}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 p-4 rounded-t-3xl shadow-lg">
        <div className="flex items-center gap-3">
          <div className={`w-3 h-3 rounded-full ${isProcessing ? 'bg-blue-500 animate-pulse' : 'bg-green-500'}`}></div>
          <span className="text-sm text-gray-700 flex-1 truncate">
            {processingStep || statusMessage}
          </span>
          {isProcessing && <LoadingSpinner />}
        </div>
        
        {/* Safe Area 지원 */}
        <div style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}></div>
      </div>
    </div>
  );
};

export default FoodDetectionApp;
